### Python Implementation

```python
def quicksort(arr):
    """
    Sorts an array using the Quick Sort algorithm.
    This is a simple, readable implementation.
    """
    # Base case: arrays with 0 or 1 element are already sorted
    if len(arr) <= 1:
        return arr

    # Choose the middle element as pivot
    pivot = arr[len(arr) // 2]

    # Partition: elements less than, equal to, and greater than pivot
    left = [x for x in arr if x < pivot]
    middle = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]

    # Recursively sort the partitions and combine
    return quicksort(left) + middle + quicksort(right)


def quicksort_inplace(arr, low=0, high=None):
    """
    In-place Quick Sort implementation (more memory efficient).
    Modifies the original array instead of creating new ones.
    """
    if high is None:
        high = len(arr) - 1

    if low < high:
        # Find partition index
        pi = partition(arr, low, high)

        # Recursively sort elements before and after partition
        quicksort_inplace(arr, low, pi - 1)
        quicksort_inplace(arr, pi + 1, high)

    return arr


def partition(arr, low, high):
    """
    Partitions the array using the last element as pivot.
    Places pivot in its correct position and returns its index.
    """
    # Choose the rightmost element as pivot
    pivot = arr[high]

    # Index of smaller element - indicates the right position
    # of pivot found so far
    i = low - 1

    for j in range(low, high):
        # If current element is smaller than or equal to pivot
        if arr[j] <= pivot:
            i += 1
            arr[i], arr[j] = arr[j], arr[i]

    # Place pivot in its correct position
    arr[i + 1], arr[high] = arr[high], arr[i + 1]
    return i + 1


# Example usage
if __name__ == "__main__":
    # Test the simple version
    data = [64, 34, 25, 12, 22, 11, 90]
    print("Original array:", data)
    sorted_data = quicksort(data)
    print("Sorted array:  ", sorted_data)

    # Test the in-place version
    data2 = [64, 34, 25, 12, 22, 11, 90]
    print("\nIn-place sorting:")
    print("Original array:", data2)
    quicksort_inplace(data2)
    print("Sorted array:  ", data2)
