    }

private:
    // Lomuto partition scheme
    static int partition(std::vector<int>& arr, int low, int high) {
        // Choose the rightmost element as pivot
        int pivot = arr[high];

        // Index of smaller element
        int i = low - 1;

        for (int j = low; j < high; j++) {
            // If current element is smaller than or equal to pivot
            if (arr[j] <= pivot) {
                i++;
                std::swap(arr[i], arr[j]);
            }
        }

        // Place pivot in its correct position
        std::swap(arr[i + 1], arr[high]);
        return i + 1;
    }

    // Alternative: Hoare partition scheme (often more efficient)
    static int partitionHoare(std::vector<int>& arr, int low, int high) {
        int pivot = arr[low];
        int i = low - 1;
        int j = high + 1;

        while (true) {
            // Find leftmost element >= pivot
            do {
                i++;
            } while (arr[i] < pivot);

            // Find rightmost element <= pivot
            do {
                j--;
            } while (arr[j] > pivot);

            // If pointers crossed, partitioning is complete
            if (i >= j) {
                return j;
            }

            std::swap(arr[i], arr[j]);
        }
    }
};

