    if (low < high) {
        // Find partition index
        const pi = partition(arr, low, high);

        // Recursively sort elements before and after partition
        quickSortInPlace(arr, low, pi - 1);
        quickSortInPlace(arr, pi + 1, high);
    }
    return arr;
